using System.ComponentModel;
using System.Text.Json;
using Microsoft.Extensions.Logging;
using ModelContextProtocol.Server;

namespace ApiMcpServer.Tools;

/// <summary>
/// MCP tools that wrap the JSONPlaceholder REST API via HttpClient.
/// Uses constructor injection â€” the SDK resolves DI services automatically
/// and keeps them out of the tool schema exposed to LLMs.
/// </summary>
[McpServerToolType]
public class JsonPlaceholderTools(HttpClient httpClient, ILogger<JsonPlaceholderTools> logger)
{
    private static readonly JsonSerializerOptions JsonOptions = new() { WriteIndented = true };

    [McpServerTool, Description("Get a post by its ID from JSONPlaceholder.")]
    public async Task<string> GetPost(
        [Description("The numeric post ID (1â€“100)")] int postId,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Fetching post {PostId}", postId);
        var json = await httpClient.GetStringAsync($"posts/{postId}", cancellationToken);
        return FormatJson(json);
    }

    [McpServerTool, Description("List all posts, optionally filtered by user ID.")]
    public async Task<string> ListPosts(
        [Description("Filter by user ID (omit to list all posts)")] int? userId = null,
        CancellationToken cancellationToken = default)
    {
        var url = userId.HasValue ? $"posts?userId={userId}" : "posts";
        logger.LogInformation("Listing posts: {Url}", url);
        var json = await httpClient.GetStringAsync(url, cancellationToken);
        return FormatJson(json);
    }

    [McpServerTool, Description("Get all comments on a specific post.")]
    public async Task<string> GetComments(
        [Description("The post ID to get comments for")] int postId,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Fetching comments for post {PostId}", postId);
        var json = await httpClient.GetStringAsync($"posts/{postId}/comments", cancellationToken);
        return FormatJson(json);
    }

    [McpServerTool, Description("Get user profile information by user ID.")]
    public async Task<string> GetUser(
        [Description("The user ID (1â€“10)")] int userId,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Fetching user {UserId}", userId);
        var json = await httpClient.GetStringAsync($"users/{userId}", cancellationToken);
        return FormatJson(json);
    }

    private static string FormatJson(string rawJson)
    {
        using var doc = JsonDocument.Parse(rawJson);
        return JsonSerializer.Serialize(doc, JsonOptions);
    }
}

